// ─────────────────────────────────────────────────────────────────────────────
// EngineScreen2Calm — Phase 2.2 wrapper
// Three sub-cause tabs (NOx, DPF, Belt). Tab A is fully ported (Phase 2.2);
// Tabs B and C show placeholders pending Phase 2.2b / 2.2c.
// Default tab matches engineSubCause prop:
//   nox → A · dpf → B · belt → C
// Triangle Protocol overlay state managed here (single overlay shared
// across tabs since visual styling is identical).
// ─────────────────────────────────────────────────────────────────────────────
function EngineScreen2Calm({ engineSubCause, onRepairChoice, costs, formatCurrency }) {
  const initialTab = engineSubCause === 'dpf' ? 'B' : engineSubCause === 'belt' ? 'C' : 'A';
  const [activeTab, setActiveTab] = useState(initialTab);
  const [protocolOpen, setProtocolOpen] = useState(false);

  return (
    <>
      <style>{ENGINE_SCREEN2_KEYFRAMES}</style>

      {/* Tab strip — 3 sub-cause buttons */}
      <div style={{ padding: '11px 14px 8px 14px', borderBottom: `0.5px solid ${T.border}`, background: T.bg }}>
        <div style={{ display: 'flex', gap: 6 }}>
          {[
            { id: 'A', label: 'NOx SENSOR' },
            { id: 'B', label: 'DPF CLOG' },
            { id: 'C', label: 'SNAPPED BELT' },
          ].map((tab) => {
            const active = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                type="button"
                onClick={() => setActiveTab(tab.id)}
                style={{
                  flex: 1,
                  fontSize: 10,
                  fontWeight: 700,
                  letterSpacing: 0.4,
                  padding: '8px 4px',
                  minHeight: 36,
                  background: active ? '#3a2818' : 'transparent',
                  color: active ? '#f0d088' : T.textMuted,
                  border: `0.5px solid ${active ? T.amber : T.border}`,
                  borderRadius: 5,
                  cursor: 'pointer',
                  fontFamily: 'inherit',
                  WebkitTapHighlightColor: 'transparent',
                }}
              >
                {tab.label}
              </button>
            );
          })}
        </div>
      </div>

      {/* Triangle Protocol button — overlay positioned absolutely on top of diorama */}
      <div style={{ position: 'relative' }}>
        <button
          type="button"
          onClick={() => setProtocolOpen(v => !v)}
          style={{
            position: 'absolute',
            right: 12,
            top: 8,
            background: 'rgba(13,17,23,0.94)',
            border: `0.5px solid rgba(63,185,80,0.5)`,
            borderRadius: 7,
            padding: '7px 9px',
            width: 130,
            minHeight: 48,
            backdropFilter: 'blur(6px)',
            cursor: 'pointer',
            fontFamily: 'inherit',
            color: 'inherit',
            textAlign: 'left',
            display: protocolOpen ? 'none' : 'block',
            zIndex: 10,
            WebkitTapHighlightColor: 'transparent',
          }}
        >
          <div style={{ display: 'flex', alignItems: 'center', gap: 5, marginBottom: 3 }}>
            <svg width="10" height="10" viewBox="0 0 12 12">
              <polygon points="6,1 11,10 1,10" fill={T.green} stroke={T.bg} strokeWidth="0.5" />
            </svg>
            <div style={{ fontSize: 10, fontWeight: 700, color: T.green, letterSpacing: 0.5 }}>TRIANGLE PROTOCOL</div>
          </div>
          <div style={{ fontSize: 12, lineHeight: 1.35, color: T.textDim }}>
            <span style={{ color: T.amberSoft }}>Divided hwy:</span>{' '}
            <span style={{ fontFamily: "'Courier New',monospace", color: '#fff', fontWeight: 600 }}>10 / 100 / 200 ft</span>
          </div>
          <div style={{ fontSize: 11, color: T.textMuted, marginTop: 3, textAlign: 'right' }}>
            <span style={{ fontWeight: 700, color: T.green }}>▾ more</span>
          </div>
        </button>

        {/* Triangle Protocol expanded panel */}
        {protocolOpen && (
          <div style={{
            position: 'absolute',
            left: 14,
            right: 14,
            top: 8,
            background: 'rgba(13,17,23,0.97)',
            border: `0.5px solid ${T.green}`,
            borderRadius: 8,
            padding: '13px 15px',
            backdropFilter: 'blur(8px)',
            zIndex: 11,
            WebkitTapHighlightColor: 'transparent',
          }}>
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 7 }}>
                <svg width="13" height="13" viewBox="0 0 12 12">
                  <polygon points="6,1 11,10 1,10" fill={T.green} stroke={T.bg} strokeWidth="0.5" />
                </svg>
                <div style={{ fontSize: 12, fontWeight: 800, color: T.green, letterSpacing: 0.6 }}>TRIANGLE PROTOCOL · 49 CFR §392.22</div>
              </div>
              <button
                type="button"
                onClick={() => setProtocolOpen(false)}
                style={{ background: 'none', border: 'none', color: T.textMuted, fontSize: 18, cursor: 'pointer', padding: '0 4px', lineHeight: 1, fontFamily: 'inherit' }}
              >×</button>
            </div>
            <div style={{ fontSize: 11, lineHeight: 1.45, color: T.textDim }}>
              <div style={{ marginBottom: 8 }}>
                <span style={{ color: T.amberSoft, fontWeight: 700 }}>Within 10 minutes</span> of stopping, deploy 3 triangles:
              </div>
              <div style={{ background: 'rgba(63,185,80,0.08)', borderLeft: `2px solid ${T.green}`, padding: '6px 9px', marginBottom: 6 }}>
                <div style={{ color: T.green, fontWeight: 700, fontSize: 10.5, letterSpacing: 0.4, marginBottom: 2 }}>DIVIDED HWY · ONE-WAY</div>
                <div style={{ color: T.textDim }}>
                  <span style={{ fontFamily: "'Courier New',monospace", color: '#fff' }}>10 ft</span> ·{' '}
                  <span style={{ fontFamily: "'Courier New',monospace", color: '#fff' }}>100 ft</span> ·{' '}
                  <span style={{ fontFamily: "'Courier New',monospace", color: '#fff' }}>200 ft</span> all rearward
                </div>
              </div>
              <div style={{ background: 'rgba(210,153,34,0.08)', borderLeft: `2px solid ${T.amber}`, padding: '6px 9px', marginBottom: 6 }}>
                <div style={{ color: T.amber, fontWeight: 700, fontSize: 10.5, letterSpacing: 0.4, marginBottom: 2 }}>TWO-LANE TWO-WAY</div>
                <div style={{ color: T.textDim }}>
                  <span style={{ fontFamily: "'Courier New',monospace", color: '#fff' }}>10 ft</span> rear ·{' '}
                  <span style={{ fontFamily: "'Courier New',monospace", color: '#fff' }}>100 ft</span> rear ·{' '}
                  <span style={{ fontFamily: "'Courier New',monospace", color: '#fff' }}>100 ft</span> forward
                </div>
              </div>
              <div style={{ background: 'rgba(248,81,73,0.08)', borderLeft: `2px solid ${T.red}`, padding: '6px 9px', marginBottom: 6 }}>
                <div style={{ color: T.red, fontWeight: 700, fontSize: 10.5, letterSpacing: 0.4, marginBottom: 2 }}>CURVE OR HILL</div>
                <div style={{ color: T.textDim }}>
                  Adjust placement to give{' '}
                  <span style={{ fontFamily: "'Courier New',monospace", color: '#fff' }}>500 ft</span> visibility to approaching traffic
                </div>
              </div>
              <div style={{ color: T.textMuted, fontSize: 10, marginTop: 8, fontStyle: 'italic' }}>
                Hazard flashers ON whether or not triangles are deployed. Triangles required regardless of weather, time of day, or duration.
              </div>
            </div>
          </div>
        )}

        {/* Render the active tab content */}
        {activeTab === 'A' && <EngineScreen2CalmTabA onRepairChoice={onRepairChoice} costs={costs} formatCurrency={formatCurrency} />}
        {activeTab === 'B' && <EngineScreen2CalmTabB onRepairChoice={onRepairChoice} costs={costs} formatCurrency={formatCurrency} />}
        {activeTab === 'C' && <EngineScreen2CalmTabC onRepairChoice={onRepairChoice} costs={costs} formatCurrency={formatCurrency} />}
      </div>
    </>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// ─────────────────────────────────────────────────────────────────────────────
// TireScreen2Calm — Phase 3.1 canonical port (Calm section of tire_screen2_v4)
// Source: tire_screen2_v4.html · ts2-sB section (display:none default in HTML)
// Renders when variant === 'tire' and the player chose PROACTIVE (pull over)
// in Screen 1, averting the blowout. 3 repair paths: Mount Spare (cheapest),
// Mobile Tire Service (mid), Tow & Replace (overkill).
// Manages its own protocolOpen state for the Triangle Protocol overlay.
// ─────────────────────────────────────────────────────────────────────────────
const BRAKE_SCREEN2_AIR_KEYFRAMES = `
@keyframes brk2a-pr { 0%, 100% { opacity: 1; transform: scale(1); } 50% { opacity: .3; transform: scale(1.5); } }
@keyframes brk2a-pa { 0%, 100% { opacity: 1; transform: scale(1); } 50% { opacity: .4; transform: scale(1.4); } }
@keyframes brk2a-hz { 0%, 33% { opacity: 1; } 50%, 100% { opacity: .18; } }
@keyframes brk2a-hzC { 0%, 33% { opacity: .55; } 50%, 100% { opacity: .08; } }
@keyframes brk2a-hzD { 0%, 33% { opacity: .35; } 50%, 100% { opacity: .12; } }
@keyframes brk2a-tb { 0%, 100% { opacity: 1; } 50% { opacity: .55; } }
@keyframes brk2a-tr { 0% { r: 2; opacity: .9; } 100% { r: 18; opacity: 0; } }
@keyframes brk2a-bp { 0%, 100% { transform: scale(1); opacity: .4; } 50% { transform: scale(1.06); opacity: .1; } }
@keyframes brk2a-driverBob { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(0.5px); } }
@keyframes brk2a-armSh { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-0.3px); } }
@keyframes brk2a-armPh { 0%, 100% { transform: translateY(0) rotate(0); } 50% { transform: translateY(-0.5px) rotate(-1deg); } }
@keyframes brk2a-phGlow { 0%, 100% { opacity: .85; filter: brightness(1); } 50% { opacity: 1; filter: brightness(1.15); } }
@keyframes brk2a-stainShimmer { 0%, 100% { opacity: .7; } 50% { opacity: .9; } }
@keyframes brk2a-flashlight { 0%, 100% { opacity: .65; } 50% { opacity: .9; } }
@keyframes brk2a-heatShim { 0%, 100% { transform: skewX(0deg); opacity: 0.35; } 50% { transform: skewX(2deg); opacity: 0.6; } }
@keyframes brk2a-airHiss { 0%, 100% { opacity: 0; transform: scale(0.6) translate(0,0); } 30% { opacity: 0.55; } 100% { opacity: 0; transform: scale(1.4) translate(-6px,-12px); } }
@keyframes brk2a-skidFade { 0%, 100% { opacity: 0.55; } 50% { opacity: 0.45; } }

/* AIR MIST — much sparser than overheat's steam, since air leaks don't visibly steam */
@keyframes brk2a-mistA1 {
  0%   { transform: translate(0,0) scale(0.4) rotate(0deg); opacity: 0; }
  15%  { transform: translate(-1px,-8px) scale(0.55) rotate(-3deg); opacity: 0.45; }
  40%  { transform: translate(-3px,-22px) scale(0.7) rotate(-7deg); opacity: 0.3; }
  100% { transform: translate(-6px,-50px) scale(0.95) rotate(-12deg); opacity: 0; }
}
@keyframes brk2a-mistA2 {
  0%   { transform: translate(0,0) scale(0.45) rotate(0); opacity: 0; }
  18%  { transform: translate(0,-6px) scale(0.6) rotate(3deg); opacity: 0.4; }
  45%  { transform: translate(-2px,-18px) scale(0.75) rotate(7deg); opacity: 0.25; }
  100% { transform: translate(-5px,-42px) scale(0.95) rotate(12deg); opacity: 0; }
}
@keyframes brk2a-mistA3 {
  0%   { transform: translate(0,0) scale(0.5) rotate(0deg); opacity: 0; }
  20%  { transform: translate(-2px,-10px) scale(0.7) rotate(-4deg); opacity: 0.35; }
  50%  { transform: translate(-5px,-26px) scale(0.85) rotate(-8deg); opacity: 0.2; }
  100% { transform: translate(-9px,-58px) scale(1.1) rotate(-14deg); opacity: 0; }
}

/* MILD VAPOR (Calm) — even smaller than crisis mist, just hints of warm compressor */
@keyframes brk2a-vapC1 {
  0%   { transform: translate(0,0) scale(0.3) rotate(0); opacity: 0; }
  25%  { transform: translate(-1px,-4px) scale(0.45) rotate(-2deg); opacity: 0.3; }
  60%  { transform: translate(-2px,-12px) scale(0.6) rotate(-5deg); opacity: 0.18; }
  100% { transform: translate(-4px,-28px) scale(0.8) rotate(-9deg); opacity: 0; }
}
@keyframes brk2a-vapC2 {
  0%   { transform: translate(0,0) scale(0.35) rotate(0); opacity: 0; }
  28%  { transform: translate(0,-3px) scale(0.5) rotate(2deg); opacity: 0.25; }
  62%  { transform: translate(-2px,-10px) scale(0.65) rotate(5deg); opacity: 0.15; }
  100% { transform: translate(-4px,-25px) scale(0.85) rotate(9deg); opacity: 0; }
}
`;

