    <button onClick={() => setProtocolOpen(p => !p)} type="button" style={{ position: 'absolute', right: '75px', top: '8px', background: 'rgba(13,17,23,0.94)', border: '0.5px solid rgba(63,185,80,0.5)', borderRadius: '7px', padding: '7px 9px', width: '130px', minHeight: '48px', backdropFilter: 'blur(6px)', cursor: 'pointer', fontFamily: 'inherit', color: 'inherit', textAlign: 'left', display: 'block', zIndex: 10 }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: '5px', marginBottom: '3px' }}><svg width="10" height="10" viewBox="0 0 12 12"><polygon points="6,1 11,10 1,10" fill="#3fb950" stroke="#0d1117" strokeWidth="0.5" /></svg><div style={{ fontSize: '10px', fontWeight: 700, color: '#3fb950', letterSpacing: '0.5px' }}>TRIANGLE PROTOCOL</div></div>
      <div style={{ fontSize: '12px', lineHeight: 1.35, color: '#c9d1d9' }}><span style={{ color: '#f0b878' }}>Divided hwy:</span> <span style={{ fontFamily: "'Courier New',monospace", color: '#fff', fontWeight: 600 }}>10 / 100 / 200 ft</span></div>
      <div style={{ fontSize: '11px', color: '#7d8590', marginTop: '3px', textAlign: 'right' }}><span id="brk2a-chevA" style={{ fontWeight: 700, color: '#3fb950' }}>{protocolOpen ? '▴ less' : '▾ more'}</span></div>
    </button>
