// ─────────────────────────────────────────────────────────────────────────────
// OverheatScreen3 — Phase 3.3 Commit D wrapper (mirrors TireScreen3 pattern)
// Tab strip dispatching between OverheatScreen3TabA (REACTIVE) and TabB (PROACTIVE).
// Includes stats-reveal sound effects (creditScoreUp/Down/proactiveSavings).
// ─────────────────────────────────────────────────────────────────────────────
function OverheatScreen3({ decision, onContinue, playSFX, costs, formatCurrency }) {
  const initialTab = decision === DECISION.PULL_OVER ? 'B' : 'A';
  const [activeTab, setActiveTab] = useState(initialTab);
  const isProactive = decision === DECISION.PULL_OVER;

  // Phase 3.3 Commit D: Stats-reveal sounds (mirrors TireScreen3 pattern).
  const statsRevealedRef = useRef(false);
  useEffect(() => {
    if (statsRevealedRef.current) return;
    statsRevealedRef.current = true;

    let revealTimer = null;
    let savingsTimer = null;

    revealTimer = setTimeout(() => {
      revealTimer = null;
      safePlaySFX(playSFX, isProactive ? 'creditScoreUp' : 'creditScoreDown');
      if (isProactive) {
        savingsTimer = setTimeout(() => {
          savingsTimer = null;
          safePlaySFX(playSFX, 'proactiveSavings');
        }, 800);
      }
    }, 300);

    return () => {
      if (revealTimer)  clearTimeout(revealTimer);
      if (savingsTimer) clearTimeout(savingsTimer);
    };
  }, [isProactive, playSFX]);

  return (
    <>
      <style>{OVERHEAT_SCREEN3_KEYFRAMES}</style>

      {/* Tab strip — REACTIVE / PROACTIVE comparison */}
      <div style={{ padding: '11px 14px 8px 14px', borderBottom: `0.5px solid ${T.border}`, background: T.bg }}>
        <div style={{ display: 'flex', gap: 6 }}>
          {[
            { id: 'A', label: 'REACTIVE · push on',     activeBg: '#3a1818', activeColor: '#ffb3b3', activeBorder: T.red },
            { id: 'B', label: 'PROACTIVE · pull over',  activeBg: '#1a3a20', activeColor: '#a0e0a8', activeBorder: T.green },
          ].map((tab) => {
            const active = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                type="button"
                onClick={() => setActiveTab(tab.id)}
                style={{
                  flex: 1,
                  fontSize: 10.5,
                  fontWeight: 700,
                  letterSpacing: 0.5,
                  padding: '8px 6px',
                  minHeight: 36,
                  background: active ? tab.activeBg : 'transparent',
                  color: active ? tab.activeColor : T.textMuted,
                  border: `0.5px solid ${active ? tab.activeBorder : T.border}`,
                  borderRadius: 5,
                  cursor: 'pointer',
                  fontFamily: 'inherit',
                  WebkitTapHighlightColor: 'transparent',
                }}
              >
                {tab.label}
              </button>
            );
          })}
        </div>
      </div>

      {activeTab === 'A' && <OverheatScreen3TabA onContinue={onContinue} costs={costs} formatCurrency={formatCurrency} />}
      {activeTab === 'B' && <OverheatScreen3TabB onContinue={onContinue} costs={costs} formatCurrency={formatCurrency} />}
    </>
  );
}

