// ─────────────────────────────────────────────────────────────────────────────
// TireScreen3 — Phase 3.1 Commit C wrapper dispatcher
// Source pattern mirrors EngineScreen3 (line ~5457 in BC.jsx).
// Default tab follows the player's Screen 1 decision; tab strip allows
// switching to view the alternative outcome for educational comparison.
// ─────────────────────────────────────────────────────────────────────────────
function TireScreen3({ decision, onContinue, playSFX, costs, formatCurrency }) {
  const initialTab = decision === DECISION.PULL_OVER ? 'B' : 'A';
  const [activeTab, setActiveTab] = useState(initialTab);
  const isProactive = decision === DECISION.PULL_OVER;

  // Phase 3.1 Commit D: Stats-reveal sounds (mirrors Screen3 fallback useEffect).
  // Fires creditScoreUp/Down on mount, plus proactiveSavings on the proactive path.
  // This logic lived only in the Phase 1 fallback; canonical S3 wrappers must
  // fire the same sounds since the parent dispatcher returns early before the
  // fallback's useEffect runs.
  const statsRevealedRef = useRef(false);
  useEffect(() => {
    if (statsRevealedRef.current) return;
    statsRevealedRef.current = true;

    // Both timers must be tracked for cleanup — ghost timer prevention.
    let revealTimer = null;
    let savingsTimer = null;

    revealTimer = setTimeout(() => {
      revealTimer = null;
      safePlaySFX(playSFX, isProactive ? 'creditScoreUp' : 'creditScoreDown');
      if (isProactive) {
        savingsTimer = setTimeout(() => {
          savingsTimer = null;
          safePlaySFX(playSFX, 'proactiveSavings');
        }, 800);
      }
    }, 300);

    return () => {
      if (revealTimer)  clearTimeout(revealTimer);
      if (savingsTimer) clearTimeout(savingsTimer);
    };
  }, [isProactive, playSFX]);

  return (
    <>
      <style>{TIRE_SCREEN3_KEYFRAMES}</style>

      {/* Tab strip — REACTIVE / PROACTIVE comparison */}
      <div style={{ padding: '11px 14px 8px 14px', borderBottom: `0.5px solid ${T.border}`, background: T.bg }}>
        <div style={{ display: 'flex', gap: 6 }}>
          {[
            { id: 'A', label: 'REACTIVE · push on', activeBg: '#3a2818', activeColor: '#f0b878', activeBorder: T.amber },
            { id: 'B', label: 'PROACTIVE · pull over', activeBg: '#1a3a20', activeColor: '#a0e0a8', activeBorder: T.green },
          ].map((tab) => {
            const active = activeTab === tab.id;
            return (
              <button
                key={tab.id}
                type="button"
                onClick={() => setActiveTab(tab.id)}
                style={{
                  flex: 1,
                  fontSize: 10.5,
                  fontWeight: 700,
                  letterSpacing: 0.5,
                  padding: '8px 6px',
                  minHeight: 36,
                  background: active ? tab.activeBg : 'transparent',
                  color: active ? tab.activeColor : T.textMuted,
                  border: `0.5px solid ${active ? tab.activeBorder : T.border}`,
                  borderRadius: 5,
                  cursor: 'pointer',
                  fontFamily: 'inherit',
                  WebkitTapHighlightColor: 'transparent',
                }}
              >
                {tab.label}
              </button>
            );
          })}
        </div>
      </div>

      {activeTab === 'A' && <TireScreen3TabA onContinue={onContinue} costs={costs} formatCurrency={formatCurrency} />}
      {activeTab === 'B' && <TireScreen3TabB onContinue={onContinue} costs={costs} formatCurrency={formatCurrency} />}
    </>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
function Screen3({
  variant,
  engineSubCause,
  electricalFailureMode,
  costs,
  decision,
  selectedRepairPath,
  formatCurrency,
  onContinue,
  playSFX,
  truckData,
}) {
  // Phase 3.2 Commit D: route brake variant to canonical air/hydraulic Screen3.
  // Sub-dispatches on truckData.brakeType. Hydraulic component injected in Commit E.
  if (variant === 'brake') {
    if (truckData?.brakeType === 'hydraulic') {
      return <BrakeScreen3Hydraulic decision={decision} onContinue={onContinue} playSFX={playSFX} costs={costs} formatCurrency={formatCurrency} />;
    } else {
      return <BrakeScreen3Air decision={decision} onContinue={onContinue} playSFX={playSFX} costs={costs} formatCurrency={formatCurrency} />;
    }
  }
  // Phase 2.5: route engine variant to canonical EngineScreen3 (Reactive/Proactive
  // tabs). Phase 3.3 added overheat. Phase 3.4 Commit D added electrical.
  if (variant === 'engine') {
    return <EngineScreen3 decision={decision} onContinue={onContinue} playSFX={playSFX} costs={costs} formatCurrency={formatCurrency} />;
  }
  if (variant === 'tire') {
    return <TireScreen3 decision={decision} onContinue={onContinue} playSFX={playSFX} costs={costs} formatCurrency={formatCurrency} />;
  }
  if (variant === 'electrical') {
    return <ElectricalScreen3 decision={decision} onContinue={onContinue} playSFX={playSFX} failureMode={electricalFailureMode} costs={costs} formatCurrency={formatCurrency} />;
  }
  if (variant === 'overheat') {
    return <OverheatScreen3 decision={decision} onContinue={onContinue} playSFX={playSFX} costs={costs} formatCurrency={formatCurrency} />;
  }

  const isProactive = decision === DECISION.PULL_OVER;
  const themeColor  = isProactive ? T.green : T.red;
  const cashImpact  = isProactive ? -580 : -2030;
  const downtime    = isProactive ? 0    : 1;
  const csaImpact   = isProactive ? 0    : -5;

  // Fire stats reveal sound on mount (one-time)
  const statsRevealedRef = useRef(false);
  useEffect(() => {
    if (statsRevealedRef.current) return;
    statsRevealedRef.current = true;

    // Both timers must be tracked for cleanup — ghost timer prevention.
    let revealTimer = null;
    let savingsTimer = null;

    // Slight delay so it lands after screen transition feels settled
    revealTimer = setTimeout(() => {
      revealTimer = null;
      safePlaySFX(playSFX, isProactive ? 'creditScoreUp' : 'creditScoreDown');
      // Proactive also gets the differential reveal sound shortly after
      if (isProactive) {
        savingsTimer = setTimeout(() => {
          savingsTimer = null;
          safePlaySFX(playSFX, 'proactiveSavings');
        }, 800);
      }
    }, 300);

    return () => {
      if (revealTimer)  clearTimeout(revealTimer);
      if (savingsTimer) clearTimeout(savingsTimer);
    };
  }, [isProactive, playSFX]);

  // Fallback for missing formatCurrency prop
  const fmt = formatCurrency || ((n) => `$${Math.abs(n).toLocaleString()}`);

  return (
    <div>
      <div
        style={{
          height: 240,
          background: T.bg,
          borderBottom: `0.5px solid ${T.border}`,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexDirection: 'column',
          gap: 6,
          padding: 16,
          textAlign: 'center',
        }}
      >
        <div
          style={{
            fontSize: 12,
            fontWeight: 700,
            color: themeColor,
            letterSpacing: 0.8,
          }}
        >
          [ SCREEN 3 · {isProactive ? 'PROACTIVE' : 'REACTIVE'} ]
        </div>
        <div style={{ fontSize: 11, color: T.textMuted, lineHeight: 1.5, maxWidth: 280 }}>
          Phase 2 will port the full {variant} variant Screen 3 from
          <br />
          <code style={{ color: T.amberSoft }}>{variant}_screen3_*.html</code>
        </div>
        <div style={{ marginTop: 8, fontSize: 10, color: T.textMuted, fontFamily: "'Courier New', monospace" }}>
          decision: {decision} · path: {selectedRepairPath}
        </div>
      </div>

      <div style={{ padding: 14 }}>
        <div
          style={{
            background: '#161b22',
            border: `0.5px solid ${T.border}`,
            borderRadius: 8,
            padding: 14,
            marginBottom: 14,
          }}
        >
          <div
            style={{
              fontSize: 12,
              fontWeight: 700,
              color: T.textMuted,
              letterSpacing: 0.6,
              marginBottom: 11,
            }}
          >
            RESOLUTION SUMMARY
          </div>

          <ResolutionRow label="Total Cost" value={`−${fmt(cashImpact)}`} color={themeColor} />
          <ResolutionRow label="Downtime" value={`${downtime} day${downtime === 1 ? '' : 's'}`} color={themeColor} />
          <ResolutionRow label="CSA Impact" value={csaImpact === 0 ? 'No change' : `${csaImpact} pts`} color={themeColor} last />
        </div>

        <button
          type="button"
          onClick={onContinue}
          style={{
            width: '100%',
            background: themeColor,
            color: T.bg,
            border: 'none',
            borderRadius: 8,
            padding: 0,
            fontSize: 15,
            fontWeight: 700,
            letterSpacing: 0.8,
            cursor: 'pointer',
            fontFamily: 'inherit',
            minHeight: 56,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: 8,
            WebkitTapHighlightColor: 'transparent',
          }}
        >
          CONTINUE TO DAY {(/* currentDay + 1 — passed via props in Phase 2 */ '?')}
        </button>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
